const event = $input.first().json.body || $input.first().json;
const session = event.data?.object || {};

const email = session.customer_details?.email || session.customer_email || 'unknown';
const amount = (session.amount_total || 0) / 100;
const currency = (session.currency || 'usd').toUpperCase();
const planName = session.metadata?.plan_name || session.display_items?.[0]?.custom?.name || 'subscription';
const customerId = session.customer || '';
const subscriptionId = session.subscription || '';

// Estimate MRR — you can replace this with a real Stripe API call
const estimatedMRR = amount; // simplified

return [{
  json: {
    email,
    amount,
    currency,
    planName,
    customerId,
    subscriptionId,
    estimatedMRR,
    timestamp: new Date().toISOString()
  }
}];

